    "id": "old-55647",
    "safeNetId": "20250905-0001",
    "name": "2025 ABC MISC LIGHTNING",
    "isoDate": "2025-08-22",
    "displayDate": "08/22/2025 12:00",
    "meta": "CA · P5EK1725 0516 · USFS",
    "state": "CA",
