    "safeNetId": "20240911-0003",
    "name": "UPPER RUBY FIRE",
    "isoDate": "2024-08-23",
    "displayDate": "08/23/2024 06:00",
    "meta": "WA · USFS",
    "state": "WA",
    "agency": "USFS",
